module signal_generator(
    input clk,
    input rst_n,
    output reg [4:0] wave
);
    reg [4:0] next_wave;
    reg state;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= 1'b0;
            wave <= 5'd0;
        end else begin
            if (state == 1'b0 && wave == 5'd31) begin
                state <= 1'b1;
            end else if (state == 1'b1 && wave == 5'd0) begin
                state <= 1'b0;
            end else begin
                wave <= next_wave;
            end
        end
    end

    always @(*) begin
        if (state == 1'b0) begin
            next_wave = wave + 1'b1;
        end else begin
            next_wave = wave - 1'b1;
        end
    end

endmodule
